parameters.new_string:
/**
 * Per-channel notification preference.
 */
export interface ChannelPreference {
  enabled: boolean;
}

/**
 * User notification preferences supporting multiple delivery channels.
 *
 * Each channel can be independently enabled/disabled. When no preferences
 * are set, the system defaults to email-only for backward compatibility.
 */
export interface NotificationPreferences {
  email: ChannelPreference;
  sms: ChannelPreference;
  webhook: ChannelPreference;
}

/**
 * Default notification preferences — email enabled, others disabled.
 * Preserves backward compatibility with the original email-only behavior.
 */
export function defaultNotificationPreferences(): NotificationPreferences {
  return {
    email: { enabled: true },
    sms: { enabled: false },
    webhook: { enabled: false },
  };
}

/**
 * User model representing a system user.
 */
export interface User {
  id: string;
  name: string;
  email: string;
  phone?: string;
  role: 'admin' | 'member' | 'viewer';
  notificationPreferences: NotificationPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for creating a new user.
 */
export interface CreateUserInput {
  name: string;
  email: string;
  phone?: string;
  role: 'admin' | 'member' | 'viewer';
  notificationPreferences?: Partial<NotificationPreferences>;
}

/**
 * Input for updating an existing user.
 */
export interface UpdateUserInput {
  name?: string;
  email?: string;
  phone?: string;
  role?: 'admin' | 'member' | 'viewer';
  notificationPreferences?: Partial<NotificationPreferences>;
}

