/**
 * Check if an adapter is enabled for a given set of notification preferences.
 * When no preferences are provided, all adapters are allowed (backward compatibility).
 */
private isAdapterEnabled(adapter: NotificationAdapter, preferences?: NotificationPreferences): boolean {
  if (!preferences) return true;
  const channelKey = ADAPTER_TO_CHANNEL[adapter.name];
  if (!channelKey) return true; // unknown adapter types are allowed by default
  return preferences[channelKey].enabled;
}

/**
 * Send a notification — stores it in memory, dispatches to enabled adapters
 * based on user preferences, and logs to notification history if enabled.
 *
 * When preferences are provided, only adapters whose channel is enabled will
 * receive the notification. When absent, all adapters fire (backward compat).
 *
 * channelRecipients allows per-channel recipient overrides (e.g., phone number
 * for SMS, webhook URL for webhook).
 */
private sendNotification(params: {
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
  preferences?: NotificationPreferences;
  channelRecipients?: Partial<Record<string, string>>;
}): void {
  const notification: Notification = {
    id: generateNotificationId(),
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    sentAt: new Date(),
  };
  this.notifications.push(notification);
  this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);

  // Log to history as in-app (always stored in memory)
  if (this.historyService) {
    this.historyService.log({
      notificationId: notification.id,
      recipient: params.recipient,
      channel: 'in-app',
      type: params.type,
      subject: params.subject,
      body: params.body,
      status: 'sent',
      sentAt: notification.sentAt,
    });
  }

  const enabledAdapters = this.adapters.filter(
    (adapter) => this.isAdapterEnabled(adapter, params.preferences),
  );

  for (const adapter of enabledAdapters) {
    const adapterRecipient = params.channelRecipients?.[adapter.name] ?? params.recipient;
    const adapterPayload = { ...notification, recipient: adapterRecipient };

    adapter.send(adapterPayload).then(() => {
      if (this.historyService) {
        this.historyService.log({
          notificationId: notification.id,
          recipient: adapterRecipient,
          channel: adapter.name as NotificationChannel,
          type: params.type,
          subject: params.subject,
          body: params.body,
          status: 'sent',
          sentAt: notification.sentAt,
        });
      }
    }).catch((error) => {
      this.logger.error(`Adapter ${adapter.name} failed: ${error}`);
      if (this.historyService) {
        this.historyService.log({
          notificationId: notification.id,
          recipient: adapterRecipient,
          channel: adapter.name as NotificationChannel,
          type: params.type,
          subject: params.subject,
          body: params.body,
          status: 'failed',
          sentAt: notification.sentAt,
        });
      }
    });
  }
}

