    function makeUser(overrides: Partial<User> = {}): User {
      return {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        notificationPreferences: defaultNotificationPreferences(),
        createdAt: new Date(),
        updatedAt: new Date(),
        ...overrides,
      };
    }

    function makeOrderCreatedEvent(user: User): OrderCreatedEvent {
      return {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: user.id,
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user,
        timestamp: new Date(),
      };
    }

